import scala.collection.mutable.{HashMap, ListBuffer, Queue}

def solve(nums: Array[Long]): Long = {
  val n = nums.length
  if (n == 0) return 0L

  val maxNum = 1000000
  val sieve = Array.fill(maxNum + 1)(true)
  sieve(0) = false
  sieve(1) = false
  for (i <- 2 to maxNum) {
    if (sieve(i)) {
      for (j <- i * i to maxNum by i) {
        sieve(j) = false
      }
    }
  }

  val valueToIndices = HashMap[Long, ListBuffer[Int]]()
  for (i <- 0 until n) {
    val num = nums(i)
    if (!valueToIndices.contains(num)) {
      valueToIndices(num) = ListBuffer()
    }
    valueToIndices(num) += i
  }

  val maxVal = nums.max.toInt
  val visited = Array.fill(n)(false)
  val queue = Queue[(Int, Int)]((0, 0))
  visited(0) = true

  while (queue.nonEmpty) {
    val (i, steps) = queue.dequeue()
    if (i == n - 1) return steps.toLong

    for (dir <- List(-1, 1)) {
      val j = i + dir
      if (j >= 0 && j < n && !visited(j)) {
        visited(j) = true
        queue.enqueue((j, steps + 1))
      }
    }

    val num = nums(i)
    if (sieve(num.toInt)) {
      val p = num.toInt
      for (m <- p to maxVal by p) {
        if (valueToIndices.contains(m)) {
          for (j <- valueToIndices(m)) {
            if (j != i && !visited(j)) {
              visited(j) = true
              queue.enqueue((j, steps + 1))
            }
          }
        }
      }
    }
  }

  -1L
}
